package com.example.mfa.security;

import java.security.SecureRandom;
import java.util.Base64;
import java.util.HexFormat;
import org.springframework.stereotype.Component;

@Component
public class BackupCodeGenerator {

    private static final SecureRandom RANDOM = new SecureRandom();

    public String generatePlainCode() {
        byte[] bytes = new byte[10];
        RANDOM.nextBytes(bytes);
        return formatCode(HexFormat.of().formatHex(bytes));
    }

    public String hashCode(String plainCode, String salt) {
        return PasswordHasher.sha256(plainCode + ":" + salt);
    }

    public String generateSalt() {
        byte[] bytes = new byte[16];
        RANDOM.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private String formatCode(String hex) {
        String upper = hex.toUpperCase();
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < upper.length(); i += 4) {
            if (i > 0) {
                sb.append('-');
            }
            sb.append(upper, i, Math.min(i + 4, upper.length()));
        }
        return sb.toString();
    }
}

package com.example.mfa.security;

import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;

public final class PasswordHasher {
    private PasswordHasher() {
    }

    public static String sha256(String value) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hashed = digest.digest(value.getBytes(StandardCharsets.UTF_8));
            StringBuilder sb = new StringBuilder();
            for (byte b : hashed) {
                sb.append(String.format("%02x", b));
            }
            return sb.toString();
        } catch (Exception e) {
            throw new IllegalStateException("Unable to hash value", e);
        }
    }
}

package com.example.mfa.service;

import com.example.mfa.domain.BackupCode;
import com.example.mfa.domain.UserAccount;
import com.example.mfa.repository.BackupCodeRepository;
import com.example.mfa.repository.UserAccountRepository;
import com.example.mfa.security.BackupCodeGenerator;
import jakarta.transaction.Transactional;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.springframework.stereotype.Service;

@Service
public class MfaService {

    private final UserAccountRepository userAccountRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final BackupCodeGenerator backupCodeGenerator;

    public MfaService(UserAccountRepository userAccountRepository,
                      BackupCodeRepository backupCodeRepository,
                      BackupCodeGenerator backupCodeGenerator) {
        this.userAccountRepository = userAccountRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.backupCodeGenerator = backupCodeGenerator;
    }

    @Transactional
    public List<String> enableTwoFactorAndGenerateBackupCodes(UUID userId, String mfaSecret) {
        UserAccount user = userAccountRepository.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        user.setMfaEnabled(true);
        user.setMfaSecret(mfaSecret);

        backupCodeRepository.findByUserOrderByCreatedAtDesc(user).forEach(backupCodeRepository::delete);

        List<String> plainCodes = new ArrayList<>();
        for (int i = 0; i < 10; i++) {
            String plain = backupCodeGenerator.generatePlainCode();
            String salt = backupCodeGenerator.generateSalt();
            BackupCode code = new BackupCode();
            code.setUser(user);
            code.setCodeHash(backupCodeGenerator.hashCode(plain, salt) + ":" + salt);
            code.setUsed(false);
            code.setCreatedAt(Instant.now());
            backupCodeRepository.save(code);
            plainCodes.add(plain);
        }

        userAccountRepository.save(user);
        return plainCodes;
    }

    @Transactional
    public AuthenticationResult authenticateWithBackupCode(String username, String backupCode) {
        UserAccount user = userAccountRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        BackupCode matched = null;
        for (BackupCode code : backupCodeRepository.findByUserOrderByCreatedAtDesc(user)) {
            if (!code.isUsed() && matches(backupCode, code.getCodeHash())) {
                matched = code;
                break;
            }
        }

        if (matched == null) {
            return AuthenticationResult.failed("Invalid backup code");
        }

        matched.setUsed(true);
        matched.setUsedAt(Instant.now());
        backupCodeRepository.save(matched);

        return AuthenticationResult.success(user.getId(), "Backup code accepted");
    }

    public List<BackupCodeStatus> getBackupCodeStatus(UUID userId) {
        UserAccount user = userAccountRepository.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        List<BackupCodeStatus> statuses = new ArrayList<>();
        for (BackupCode code : backupCodeRepository.findByUserOrderByCreatedAtDesc(user)) {
            statuses.add(new BackupCodeStatus(code.getId(), code.isUsed(), code.getCreatedAt(), code.getUsedAt()));
        }
        return statuses;
    }

    private boolean matches(String plainCode, String stored) {
        String[] parts = stored.split(":");
        if (parts.length != 2) {
            return false;
        }
        String hash = parts[0];
        String salt = parts[1];
        return backupCodeGenerator.hashCode(plainCode, salt).equals(hash);
    }
}

