package com.example.mfa.web;

import com.example.mfa.service.AuthenticationResult;
import com.example.mfa.service.BackupCodeStatus;
import com.example.mfa.service.MfaService;
import java.util.List;
import java.util.UUID;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {

    private final MfaService mfaService;

    public MfaController(MfaService mfaService) {
        this.mfaService = mfaService;
    }

    @PostMapping("/enable/{userId}")
    public ResponseEntity<List<String>> enableMfa(@PathVariable UUID userId, @RequestBody EnableMfaRequest request) {
        return ResponseEntity.ok(mfaService.enableTwoFactorAndGenerateBackupCodes(userId, request.getMfaSecret()));
    }

    @PostMapping("/authenticate/backup-code")
    public ResponseEntity<AuthenticationResult> authenticateWithBackupCode(@RequestBody BackupCodeLoginRequest request) {
        AuthenticationResult result = mfaService.authenticateWithBackupCode(request.getUsername(), request.getBackupCode());
        return result.isSuccess() ? ResponseEntity.ok(result) : ResponseEntity.status(401).body(result);
    }

    @GetMapping("/backup-codes/{userId}")
    public ResponseEntity<List<BackupCodeStatus>> getBackupCodeStatus(@PathVariable UUID userId) {
        return ResponseEntity.ok(mfaService.getBackupCodeStatus(userId));
    }
}

